#### **Webhook Registration Strategy:**
For a GitHub webhook, you'd follow the entity route pattern but with these modifications:

```typescript
// new file: app/src/server/webhooks/github-webhook-route.ts

export function createGithubWebhookHandler(
  deps: ServerDependencies
): (request: Request) => Promise<Response> {
  return (request: Request) => handleGithubWebhook(deps, request);
}

async function handleGithubWebhook(
  deps: ServerDependencies,
  request: Request
): Promise<Response> {
  const signature = request.headers.get("x-hub-signature-256");
  if (!signature || !verifyGithubSignature(signature, await request.clone().text())) {
    return jsonError("unauthorized", 401);
  }

  let body: any;
  try {
    body = await request.json();
  } catch {
    return jsonError("invalid JSON", 400);
  }

  const event = request.headers.get("x-github-event");
  if (event !== "push") {
    return jsonResponse({ status: "ignored" }, 200);
  }

  // Register SSE stream for async processing
  const webhookId = randomUUID();
  deps.sse.registerMessage(webhookId);

  // Start async processing (fire and forget)
  void processGithubPush({
    deps,
    webhookId,
    payload: body,
  }).catch((error) => {
    logError("github.webhook.process.failed", "Failed to process GitHub webhook", error);
    deps.sse.emitEvent(webhookId, {
      type: "error",
      error: "Failed to process webhook",
    });
  });

  return jsonResponse({
    status: "accepted",
    webhookId,
    streamUrl: `/api/webhooks/github/stream/${webhookId}`,
  }, 202);
}

async function processGithubPush(input: {
  deps: ServerDependencies;
  webhookId: string;
  payload: any;
}): Promise<void> {
  deps.sse.emitEvent(input.webhookId, {
    type: "token",
    content: "Processing GitHub commits...",
  });

  // Extract commits, create entities, emit events
  const commits = input.payload.commits || [];
  for (const commit of commits) {
    // Create task/observation from commit
    const taskRecord = new RecordId("task", randomUUID());
    await input.deps.surreal.create(taskRecord).content({
      title: commit.message,
      status: "open",
      source: "github_webhook",
      created_at: new Date(),
    });

    input.deps.sse.emitEvent(input.webhookId, {
      type: "token",
      content: `Created task from commit: ${commit.id.slice(0, 7)}`,
    });
  }

  input.deps.sse.emitEvent(input.webhookId, {
    type: "done",
  });
}
```

Then register in `start-server.ts`:
```typescript
