  POST: withRequestLogging(
    "POST /api/webhooks/github/commits",
    "POST",
    (request) => githubWebhookHandler(request)
  ),
},
"/api/webhooks/github/stream/:webhookId": {
  GET: withRequestLogging(
    "GET /api/webhooks/github/stream/:webhookId",
    "GET",
    (request) => deps.sse.handleStreamRequest(request.params.webhookId)
  ),
},
```

