 20→import { fireDescriptionUpdates } from "../descriptions/triggers";
 21→import type { DescriptionTarget } from "../descriptions/types";
 22→import { loadWorkspaceProjects } from "../workspace/workspace-scope";
 23→import { postValidateEntities, postValidateRelationships } from "./validation";
 24→
 25→export async function persistExtractionOutput(input: {
 26→  surreal: Surreal;
 27→  extractionModel: any;
 28→  embeddingModel: any;
 29→  embeddingDimension: number;
 30→  extractionModelId: string;
 31→  extractionStoreThreshold: number;
 32→  workspaceRecord: RecordId<"workspace", string>;
 33→  sourceRecord: SourceRecord;
 34→  sourceKind: SourceKind;
 35→  sourceLabel?: string;
 36→  promptText: string;
 37→  output: ExtractionPromptOutput;
 38→  sourceMessageRecord?: RecordId<"message", string>;
 39→  sourceChunkRecord?: RecordId<"document_chunk", string>;
 40→  extractionHistoryMessageIds?: string[];
 41→  now: Date;
 42→}): Promise<PersistExtractionResult> {
 43→  const startedAt = performance.now();
 44→  logInfo("extraction.persist.started", "Extraction persistence started", {
 45→    workspaceId: input.workspaceRecord.id as string,
 46→    sourceKind: input.sourceKind,
 47→    sourceId: input.sourceRecord.id as string,
 48→    candidateEntityCount: input.output.entities.length,
 49→    candidateRelationshipCount: input.output.relationships.length,
 50→  });
 51→
 52→  try {
 53→    const entities = postValidateEntities({
 54→      entities: input.output.entities,
 55→      sourceText: input.promptText,
 56→      storeThreshold: input.extractionStoreThreshold,
 57→    });
 58→    if (input.sourceKind === "message" && !input.sourceMessageRecord) {
 59→      throw new Error("message extraction persistence requires sourceMessageRecord");
 60→    }
 61→
 62→    const extractionHistoryMessageIds = new Set(input.extractionHistoryMessageIds ?? []);
 63→    const relationships = postValidateRelationships({
 64→      relationships: input.output.relationships,
 65→      storeThreshold: input.extractionStoreThreshold,
 66→    }).map((relationship) => ({
 67→      ...relationship,
 68→      kind: normalizeRelationshipKind(relationship.kind),
 69→    }));
 70→
 71→    const persistedEntities: ExtractedEntity[] = [];
 72→    const persistedRelationships: ExtractedRelationship[] = [];
 73→    const seeds: OnboardingSeedItem[] = [];
 74→    const embeddingTargets: Array<{ record: GraphEntityRecord; text: string }> = [];
 75→    const entityByTempId = new Map<string, TempEntityReference>();
 76→    const unresolvedAssigneeNames = new Set<string>();
 77→
 78→    const workspaceProjects = await loadWorkspaceProjects(input.surreal, input.workspaceRecord);
 79→
 80→    for (const extracted of entities) {
 81→      const resolvedFromMessageId = resolveValidatedResolvedFromMessageId({
 82→        resolvedFromMessageId: "resolvedFromMessageId" in extracted ? extracted.resolvedFromMessageId : undefined,
 83→        sourceKind: input.sourceKind,
 84→        sourceMessageId: input.sourceMessageRecord?.id as string | undefined,
 85→        extractionHistoryMessageIds,
 86→      });
 87→      const resolvedFromMessageRecord = resolvedFromMessageId
 88→        ? new RecordId("message", resolvedFromMessageId)
 89→        : undefined;
 90→
 91→      const persisted = await upsertGraphEntity({
 92→        surreal: input.surreal,
 93→        embeddingModel: input.embeddingModel,
 94→        embeddingDimension: input.embeddingDimension,
 95→        extractionModelId: input.extractionModelId,
 96→        workspaceRecord: input.workspaceRecord,
 97→        workspaceProjects,
 98→        sourceRecord: input.sourceRecord,
 99→        sourceKind: input.sourceKind,
100→        promptText: input.promptText,
101→        extracted: extracted as ExtractionPromptEntity & { kind: Exclude<EntityKind, "workspace" | "person" | "observation"> },
102→        sourceMessageRecord: input.sourceMessageRecord,
103→        sourceChunkRecord: input.sourceChunkRecord,
104→        resolvedFromMessageRecord,
105→        now: input.now,
106→      });
107→
108→      entityByTempId.set(extracted.tempId, {
109→        record: persisted.record,
110→        text: persisted.text,
111→        id: persisted.record.id as string,
112→        kind: persisted.kind,
113→      });
114→
115→      const extractedCategory = "category" in extracted ? extracted.category : undefined;
116→      const extractedPriority = "priority" in extracted ? extracted.priority : undefined;
117→
118→      persistedEntities.push({
119→        id: persisted.record.id as string,
120→        kind: persisted.kind,
121→        text: persisted.text,
122→        confidence: extracted.confidence,
