```typescript
import { randomUUID } from "node:crypto";
import { RecordId, type Surreal } from "surrealdb";
import type { ServerDependencies } from "../runtime/types";
import { resolveWorkspaceRecord } from "../workspace/workspace-scope";
import { HttpError } from "../http/errors";
import { jsonError, jsonResponse } from "../http/response";
import { logError, logInfo, logWarn } from "../http/observability";
import { processGitCommit } from "./github-commit-processor";

export function createGitHubWebhookHandler(
  deps: ServerDependencies,
): (workspaceId: string, request: Request) => Promise<Response> {
  return (workspaceId: string, request: Request) =>
    handleGitHubWebhook(deps, workspaceId, request);
}

async function handleGitHubWebhook(
  deps: ServerDependencies,
  workspaceId: string,
  request: Request,
): Promise<Response> {
  // 1. Verify GitHub signature (HMAC SHA-256)
  // 2. Check X-GitHub-Event header == "push"
  // 3. Parse body, extract commits array + ref
  // 4. Filter: only process if ref matches default branch (refs/heads/main or refs/heads/master)
  // 5. Resolve workspace record
  // 6. For each commit: call processGitCommit()
  // 7. Return 200 with summary
}
```

**Signature verification** using `GITHUB_WEBHOOK_SECRET`:
```typescript
async function verifyGitHubSignature(
  secret: string,
  payload: string,
  signature: string,
): Promise<boolean> {
  const encoder = new TextEncoder();
  const key = await crypto.subtle.importKey(
    "raw",
    encoder.encode(secret),
    { name: "HMAC", hash: "SHA-256" },
    false,
    ["sign"],
  );
  const sig = await crypto.subtle.sign("HMAC", key, encoder.encode(payload));
  const computed = `sha256=${Buffer.from(sig).toString("hex")}`;
  return computed === signature;
}
```

**Push event payload parsing** -- extract only the fields needed:
```typescript
type GitHubPushEvent = {
  ref: string;                    // "refs/heads/main"
  repository: {
    full_name: string;            // "owner/repo"
    default_branch: string;       // "main"
    html_url: string;
  };
  commits: Array<{
    id: string;                   // sha
    message: string;
    timestamp: string;            // ISO 8601
    url: string;                  // commit URL on GitHub
    author: {
      name: string;
      email: string;
      username?: string;
    };
  }>;
};
```

**Branch filtering**: compare `event.ref` against `refs/heads/${event.repository.default_branch}`. Reject non-default-branch pushes with 200 (accepted but not processed) to avoid GitHub retries.

