395→DEFINE FUNCTION fn::entity_search_project($q: string, $limit: int, $workspace: record<workspace>, $project: record<project>) {
396→  LET $query = string::lowercase(string::trim($q));
397→  LET $safe_limit = math::min([math::max([$limit, 1]), 100]);
398→  LET $workspace_conversations = SELECT VALUE id FROM conversation WHERE workspace = $workspace;
399→  LET $workspace_messages = SELECT VALUE id FROM message WHERE conversation IN $workspace_conversations;
400→  LET $project_entity_ids = SELECT VALUE `in` FROM belongs_to WHERE out = $project;
401→
402→  LET $task_rows = SELECT
403→    id,
404→    "task" AS kind,
405→    title AS text,
406→    extraction_confidence AS confidence,
407→    source_message AS sourceMessage,
408→    priority,
409→    created_at
410→  FROM task
411→  WHERE source_message != NONE
412→    AND source_message IN $workspace_messages
413→    AND extraction_confidence != NONE
414→    AND id IN $project_entity_ids
415→    AND string::contains(string::lowercase(title), $query)
416→  ORDER BY created_at DESC
417→  LIMIT $safe_limit;
418→
419→  LET $decision_rows = SELECT
420→    id,
421→    "decision" AS kind,
422→    summary AS text,
423→    extraction_confidence AS confidence,
424→    source_message AS sourceMessage,
425→    priority,
426→    created_at
427→  FROM decision
428→  WHERE source_message != NONE
429→    AND source_message IN $workspace_messages
430→    AND extraction_confidence != NONE
431→    AND id IN $project_entity_ids
432→    AND string::contains(string::lowercase(summary), $query)
433→  ORDER BY created_at DESC
434→  LIMIT $safe_limit;
435→
436→  LET $question_rows = SELECT
437→    id,
438→    "question" AS kind,
439→    text AS text,
440→    extraction_confidence AS confidence,
441→    source_message AS sourceMessage,
442→    priority,
443→    created_at
444→  FROM question
445→  WHERE source_message != NONE
446→    AND source_message IN $workspace_messages
447→    AND extraction_confidence != NONE
448→    AND id IN $project_entity_ids
449→    AND string::contains(string::lowercase(text), $query)
450→  ORDER BY created_at DESC
451→  LIMIT $safe_limit;
452→
453→  RETURN array::flatten([$task_rows, $decision_rows, $question_rows]);
454→};
455→
456→DEFINE FUNCTION fn::conversation_recent($conversation: record<conversation>, $limit: int) {
457→  LET $safe_limit = math::min([math::max([$limit, 1]), 50]);
458→  RETURN SELECT id, role, text, createdAt
459→  FROM message
460→  WHERE conversation = $conversation
461→  ORDER BY createdAt DESC
462→  LIMIT $safe_limit;
463→};
