465→DEFINE FUNCTION fn::entity_neighbors($entity: record) {
466→  RETURN SELECT
467→    ->entity_relation->(workspace, project, person, feature, task, decision, question) AS outgoing,
468→    <-entity_relation<-(workspace, project, person, feature, task, decision, question) AS incoming
469→  FROM $entity;
470→};
