 19→export async function startServer(): Promise<void> {
 20→  const config = loadServerConfig();
 21→  const runtime = await createRuntimeDependencies(config);
 22→  await ensureDefaultWorkspaceProjectScope(runtime.surreal);
 23→
 24→  const deps: ServerDependencies = {
 25→    config,
 26→    surreal: runtime.surreal,
 27→    assistantModel: runtime.assistantModel,
 28→    extractionModel: runtime.extractionModel,
 29→    pmModel: runtime.pmModel,
 30→    embeddingModel: runtime.embeddingModel,
 31→    sse: createSseRegistry(),
 32→  };
 33→
 34→  const workspaceHandlers = createWorkspaceRouteHandlers(deps);
 35→  const chatHandlers = createChatIngressHandlers(deps);
 36→  const entitySearchHandler = createEntitySearchHandler(deps);
 37→  const graphHandler = createGraphRouteHandler(deps);
 38→  const entityDetailHandler = createEntityDetailHandler(deps);
 39→  const entityActionsHandler = createEntityActionsHandler(deps);
 40→  const workItemAcceptHandler = createWorkItemAcceptHandler(deps);
 41→  const branchConversationHandler = createBranchConversationHandler(deps);
 42→
 43→  const server = Bun.serve({
 44→    port: config.port,
 45→    idleTimeout: 0,
 46→    routes: {
 47→      "/healthz": {
 48→        GET: withRequestLogging("GET /healthz", "GET", async () => jsonResponse({ status: "ok" }, 200)),
 49→      },
 50→      "/api/workspaces": {
 51→        POST: withRequestLogging("POST /api/workspaces", "POST", (request) => workspaceHandlers.handleCreateWorkspace(request)),
 52→      },
 53→      "/api/workspaces/:workspaceId/bootstrap": {
 54→        GET: withRequestLogging(
 55→          "GET /api/workspaces/:workspaceId/bootstrap",
 56→          "GET",
 57→          (request) => workspaceHandlers.handleWorkspaceBootstrap(request.params.workspaceId),
 58→        ),
 59→      },
 60→      "/api/workspaces/:workspaceId/sidebar": {
 61→        GET: withRequestLogging(
 62→          "GET /api/workspaces/:workspaceId/sidebar",
 63→          "GET",
 64→          (request) => workspaceHandlers.handleWorkspaceSidebar(request.params.workspaceId),
 65→        ),
 66→      },
 67→      "/api/workspaces/:workspaceId/conversations/:conversationId": {
 68→        GET: withRequestLogging(
 69→          "GET /api/workspaces/:workspaceId/conversations/:conversationId",
 70→          "GET",
 71→          (request) =>
 72→            workspaceHandlers.handleWorkspaceConversation(
 73→              request.params.workspaceId,
 74→              request.params.conversationId,
 75→            ),
 76→        ),
 77→      },
 78→      "/api/chat/messages": {
 79→        POST: withRequestLogging("POST /api/chat/messages", "POST", (request) => chatHandlers.handlePostChatMessage(request)),
 80→      },
 81→      "/api/chat/stream/:messageId": {
 82→        GET: withRequestLogging("GET /api/chat/stream/:messageId", "GET", (request) =>
 83→          chatHandlers.handleChatStream(request.params.messageId),
 84→        ),
 85→      },
 86→      "/api/entities/search": {
 87→        GET: withRequestLogging("GET /api/entities/search", "GET", (request) => entitySearchHandler(new URL(request.url))),
 88→      },
 89→      "/api/graph/:workspaceId": {
 90→        GET: withRequestLogging("GET /api/graph/:workspaceId", "GET", (request) =>
 91→          graphHandler(request.params.workspaceId, new URL(request.url)),
 92→        ),
 93→      },
 94→      "/api/entities/:entityId": {
 95→        GET: withRequestLogging("GET /api/entities/:entityId", "GET", (request) =>
 96→          entityDetailHandler(request.params.entityId, new URL(request.url)),
 97→        ),
 98→      },
 99→      "/api/entities/:entityId/actions": {
100→        POST: withRequestLogging("POST /api/entities/:entityId/actions", "POST", (request) =>
101→          entityActionsHandler(request.params.entityId, request),
102→        ),
103→      },
104→      "/api/workspaces/:workspaceId/conversations/:parentId/branch": {
105→        POST: withRequestLogging(
106→          "POST /api/workspaces/:workspaceId/conversations/:parentId/branch",
107→          "POST",
108→          (request) =>
109→            branchConversationHandler(
110→              request.params.workspaceId,
111→              request.params.parentId,
112→              request,
113→            ),
114→        ),
115→      },
116→      "/api/workspaces/:workspaceId/work-items/accept": {
117→        POST: withRequestLogging(
118→          "POST /api/workspaces/:workspaceId/work-items/accept",
119→          "POST",
120→          (request) => workItemAcceptHandler(request.params.workspaceId, request),
121→        ),
122→      },
123→      "/": appHtml,
124→      "/*": appHtml,
125→    },
126→  });
127→
128→  logInfo("server.started", "Brain app server started", {
129→    port: server.port,
130→    host: "127.0.0.1",
131→    assistantModelId: config.assistantModelId,
132→    extractionModelId: config.extractionModelId,
133→    pmModelId: config.pmModelId,
134→    embeddingModelId: config.embeddingModelId,
135→    embeddingDimension: config.embeddingDimension,
136→    extractionStoreThreshold: config.extractionStoreThreshold,
137→    extractionDisplayThreshold: config.extractionDisplayThreshold,
138→    surrealTransport: config.surrealUrl.startsWith("wss://")
139→      ? "wss"
140→      : config.surrealUrl.startsWith("ws://")
141→        ? "ws"
142→        : config.surrealUrl.startsWith("https://")
143→          ? "https"
144→          : "http",
145→    surrealNamespace: config.surrealNamespace,
146→    surrealDatabase: config.surrealDatabase,
147→    openRouterReasoningEnabled: config.openRouterReasoning !== undefined,
148→  });
149→}
