 4→export function resolveValidatedResolvedFromMessageId(input: {
 5→  resolvedFromMessageId?: string;
 6→  sourceKind: SourceKind;
 7→  sourceMessageId?: string;
 8→  extractionHistoryMessageIds: Set<string>;
 9→}): string | undefined {
10→  const resolvedFromMessageId = input.resolvedFromMessageId?.trim();
11→  if (!resolvedFromMessageId) {
12→    return undefined;
13→  }
14→
15→  if (input.sourceKind !== "message") {
16→    throw new Error("resolvedFromMessageId is only valid for message extraction sources");
17→  }
18→
19→  if (!input.sourceMessageId || input.sourceMessageId.trim().length === 0) {
20→    throw new Error("resolvedFromMessageId requires sourceMessageId");
21→  }
22→
23→  if (resolvedFromMessageId === input.sourceMessageId) {
24→    logWarn("extraction.provenance.self_reference", "LLM returned resolvedFromMessageId matching current source message; discarding", {
25→      resolvedFromMessageId,
26→      sourceMessageId: input.sourceMessageId,
27→    });
28→    return undefined;
29→  }
30→
31→  if (!input.extractionHistoryMessageIds.has(resolvedFromMessageId)) {
32→    logWarn("extraction.provenance.unknown_message", "LLM returned resolvedFromMessageId not in conversation history; discarding", {
33→      resolvedFromMessageId,
34→    });
35→    return undefined;
36→  }
37→
38→  return resolvedFromMessageId;
39→}
