 1→import { randomUUID } from "node:crypto";
 2→import { runWithRequestContext } from "../request-context";
 3→import { jsonError, withRequestIdHeader } from "./response";
 4→import { elapsedMs, logDebug, logError, logInfo } from "./observability";
 5→
 6→export type RouteRequest = Request & {
 7→  params: Record<string, string>;
 8→};
 9→
10→export type RouteHandler = (request: RouteRequest) => Response | Promise<Response>;
11→
12→export function withRequestLogging(route: string, method: string, handler: RouteHandler): RouteHandler {
13→  return async (request: RouteRequest) => {
14→    const startedAt = performance.now();
15→    const headerValue = request.headers.get("x-request-id")?.trim();
16→    const requestId = headerValue && headerValue.length > 0 ? headerValue : randomUUID();
17→    const path = new URL(request.url).pathname;
18→
19→    return runWithRequestContext(
20→      {
21→        requestId,
22→        method,
23→        route,
24→        path,
25→      },
26→      async () => {
27→        logDebug("http.request.received", "HTTP request received");
28→
29→        try {
30→          const response = await handler(request);
31→          const responseWithRequestId = withRequestIdHeader(response, requestId);
32→          logInfo("http.request.completed", "HTTP request completed", {
33→            statusCode: responseWithRequestId.status,
34→            durationMs: elapsedMs(startedAt),
35→          });
36→          return responseWithRequestId;
37→        } catch (error) {
38→          logError("http.request.failed", "HTTP request failed", error, {
39→            durationMs: elapsedMs(startedAt),
40→          });
41→          const fallback = jsonError("internal server error", 500);
42→          return withRequestIdHeader(fallback, requestId);
43→        }
44→      },
45→    );
46→  };
47→}
