470→export function normalizeRelationshipKind(value: string): string {
471→  return value
472→    .trim()
473→    .replace(/[^a-zA-Z0-9]+/g, "_")
474→    .replace(/_+/g, "_")
475→    .replace(/^_/, "")
476→    .replace(/_$/, "")
477→    .toUpperCase();
478→}
