480→function cosineSimilarity(a: number[], b: number[]): number {
481→  if (a.length !== b.length) {
482→    return -1;
483→  }
484→
485→  let dot = 0;
486→  let normA = 0;
487→  let normB = 0;
488→
489→  for (let i = 0; i < a.length; i += 1) {
490→    dot += a[i] * b[i];
491→    normA += a[i] * a[i];
492→    normB += b[i] * b[i];
493→  }
494→
495→  if (normA === 0 || normB === 0) {
496→    return -1;
497→  }
498→
499→  return dot / (Math.sqrt(normA) * Math.sqrt(normB));
500→}
