251→async function applyAssigneeReference(input: {
252→  surreal: Surreal;
253→  workspaceRecord: RecordId<"workspace", string>;
254→  entityRecord: GraphEntityRecord;
255→  entityKind: Exclude<EntityKind, "workspace" | "person" | "observation">;
256→  assigneeName: string;
257→  now: Date;
258→}): Promise<{ resolved: boolean; assigneeName: string }> {
259→  const assigneeName = input.assigneeName.trim();
260→  if (assigneeName.length === 0) {
261→    return { resolved: true, assigneeName };
262→  }
263→
264→  const personRecord = await findWorkspacePersonByName({
265→    surreal: input.surreal,
266→    workspaceRecord: input.workspaceRecord,
267→    personName: assigneeName,
268→  });
269→
270→  const patch = resolvePersonAttributionPatch({
271→    targetKind: input.entityKind,
272→    assigneeName,
273→    ...(personRecord ? { personRecordId: personRecord.id as string } : {}),
274→  });
275→
276→  if (patch.kind === "feature") {
277→    if (patch.field === "owner" && personRecord) {
278→      await input.surreal.update(input.entityRecord as RecordId<"feature", string>).merge({
279→        owner: personRecord,
280→        updated_at: input.now,
281→      });
282→      return { resolved: true, assigneeName };
283→    }
284→
285→    await input.surreal.update(input.entityRecord as RecordId<"feature", string>).merge({
286→      owner_name: patch.value,
287→      updated_at: input.now,
288→    });
289→    return { resolved: false, assigneeName };
290→  }
291→
292→  if (patch.kind === "task") {
293→    if (patch.field === "owner" && personRecord) {
294→      await input.surreal.update(input.entityRecord as RecordId<"task", string>).merge({
295→        owner: personRecord,
296→        updated_at: input.now,
297→      });
298→      return { resolved: true, assigneeName };
299→    }
300→
301→    await input.surreal.update(input.entityRecord as RecordId<"task", string>).merge({
302→      owner_name: patch.value,
303→      updated_at: input.now,
304→    });
305→    return { resolved: false, assigneeName };
306→  }
307→
308→  if (patch.kind === "decision") {
309→    if (patch.field === "decided_by" && personRecord) {
310→      await input.surreal.update(input.entityRecord as RecordId<"decision", string>).merge({
311→        decided_by: personRecord,
312→        updated_at: input.now,
313→      });
314→      return { resolved: true, assigneeName };
315→    }
316→
317→    await input.surreal.update(input.entityRecord as RecordId<"decision", string>).merge({
318→      decided_by_name: patch.value,
319→      updated_at: input.now,
320→    });
321→    return { resolved: false, assigneeName };
322→  }
323→
324→  if (patch.field === "assigned_to" && personRecord) {
325→    await input.surreal.update(input.entityRecord as RecordId<"question", string>).merge({
326→      assigned_to: personRecord,
327→      updated_at: input.now,
328→    });
329→    return { resolved: true, assigneeName };
330→  }
331→
332→  await input.surreal.update(input.entityRecord as RecordId<"question", string>).merge({
333→    assigned_to_name: patch.value,
334→    updated_at: input.now,
335→  });
336→  return { resolved: false, assigneeName };
337→}
