 32→async function handleAcceptWorkItem(
 33→  deps: ServerDependencies,
 34→  workspaceId: string,
 35→  request: Request,
 36→): Promise<Response> {
 37→  let body: unknown;
 38→  try {
 39→    body = await request.json();
 40→  } catch {
 41→    return jsonError("invalid JSON body", 400);
 42→  }
 43→
 44→  const parsed = acceptWorkItemSchema.safeParse(body);
 45→  if (!parsed.success) {
 46→    return jsonError(`invalid work item: ${parsed.error.message}`, 400);
 47→  }
 48→
 49→  const item = parsed.data;
 50→
 51→  let workspaceRecord: RecordId<"workspace", string>;
 52→  try {
 53→    workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
 54→  } catch (error) {
 55→    if (error instanceof HttpError) {
 56→      return jsonError(error.message, error.status);
 57→    }
 58→    logError("work-item.accept.workspace_resolve.failed", "Failed to resolve workspace", error, { workspaceId });
 59→    return jsonError("failed to resolve workspace", 500);
 60→  }
 61→
 62→  try {
 63→    const now = new Date();
 64→    const embedding = await createEmbeddingVector(
 65→      deps.embeddingModel,
 66→      item.title,
 67→      deps.config.embeddingDimension,
 68→    );
 69→
 70→    const entityId = randomUUID();
 71→
 72→    if (item.kind === "task") {
 73→      const taskRecord = new RecordId("task", entityId);
 74→      await deps.surreal.create(taskRecord).content({
 75→        title: item.title,
 76→        status: "open",
 77→        ...(item.category ? { category: item.category } : {}),
 78→        ...(item.priority ? { priority: item.priority } : {}),
 79→        ...(embedding ? { embedding } : {}),
 80→        created_at: now,
 81→        updated_at: now,
 82→      });
 83→
 84→      if (item.project) {
 85→        try {
 86→          const projectRecord = await resolveWorkspaceProjectRecord({
 87→            surreal: deps.surreal,
 88→            workspaceRecord,
 89→            projectInput: item.project,
 90→          });
 91→          await deps.surreal
 92→            .relate(taskRecord, new RecordId("belongs_to", randomUUID()), projectRecord, {
 93→              added_at: now,
 94→            })
 95→            .output("after");
 96→        } catch {
 97→          // project resolution is best-effort; task still created
 98→        }
 99→      }
100→
101→      void seedDescriptionEntry({
102→        surreal: deps.surreal,
103→        targetRecord: taskRecord,
104→        text: item.rationale,
105→        reasoning: "Created from work item suggestion",
106→        triggeredBy: [],
107→      }).catch(() => undefined);
108→
109→      logInfo("work-item.accept.task.created", "Task created from work item suggestion", {
110→        workspaceId,
111→        entityId,
112→        title: item.title,
113→      });
114→
115→      return jsonResponse({ entityId: `task:${entityId}` }, 201);
116→    }
117→
118→    // feature
119→    const featureRecord = new RecordId("feature", entityId);
120→    await deps.surreal.create(featureRecord).content({
121→      name: item.title,
122→      status: "active",
123→      ...(item.category ? { category: item.category } : {}),
124→      ...(embedding ? { embedding } : {}),
125→      created_at: now,
126→      updated_at: now,
127→    });
128→
129→    if (item.project) {
130→      try {
131→        const projectRecord = await resolveWorkspaceProjectRecord({
132→          surreal: deps.surreal,
133→          workspaceRecord,
134→          projectInput: item.project,
135→        });
136→        await ensureProjectFeatureEdge(deps.surreal, projectRecord, featureRecord, now);
137→
138→        void fireDescriptionUpdates({
139→          surreal: deps.surreal,
140→          extractionModel: deps.extractionModel,
141→          trigger: {
142→            kind: "feature_created",
143→            entity: featureRecord,
144→            summary: `Feature added: ${item.title}`,
145→          },
146→        }).catch(() => undefined);
147→      } catch {
148→        // project resolution is best-effort; feature still created
149→      }
150→    }
151→
152→    void seedDescriptionEntry({
153→      surreal: deps.surreal,
154→      targetRecord: featureRecord,
155→      text: item.rationale,
156→      reasoning: "Created from work item suggestion",
157→      triggeredBy: [],
158→    }).catch(() => undefined);
159→
160→    logInfo("work-item.accept.feature.created", "Feature created from work item suggestion", {
161→      workspaceId,
162→      entityId,
163→      title: item.title,
164→    });
165→
166→    return jsonResponse({ entityId: `feature:${entityId}` }, 201);
167→  } catch (error) {
168→    logError("work-item.accept.failed", "Failed to accept work item", error, {
169→      workspaceId,
170→      kind: item.kind,
171→      title: item.title,
172→    });
173→    const message = error instanceof Error ? error.message : "work item accept failed";
174→    return jsonError(message, 500);
175→  }
176→}
