 28→  try {
 29→    body = await request.json() as EntityActionRequest;
 30→  } catch {
 31→    return jsonError("invalid JSON body", 400);
 32→  }
 33→
 34→  if (!body.action || !["confirm", "override", "complete", "set_priority"].includes(body.action)) {
 35→    return jsonError("action must be one of: confirm, override, complete, set_priority", 400);
 36→  }
 37→
 38→  const url = new URL(request.url);
 39→  const workspaceId = url.searchParams.get("workspaceId")?.trim();
 40→  if (!workspaceId) {
 41→    return jsonError("workspaceId is required", 400);
 42→  }
 43→
 44→  let workspaceRecord;
 45→  try {
 46→    workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
 47→  } catch (error) {
 48→    if (error instanceof HttpError) {
 49→      return jsonError(error.message, error.status);
 50→    }
 51→    logError("entity.action.workspace_resolve.failed", "Failed to resolve workspace", error, { workspaceId });
 52→    return jsonError("failed to resolve workspace", 500);
 53→  }
 54→
 55→  try {
 56→    const entityTables: GraphEntityTable[] = ["workspace", "project", "person", "feature", "task", "decision", "question"];
 57→    const entityRecord = parseRecordIdString(entityId, entityTables);
 58→    const scoped = await isEntityInWorkspace(deps.surreal, workspaceRecord, entityRecord);
 59→    if (!scoped) {
 60→      return jsonError("entity is outside the current workspace scope", 403);
 61→    }
 62→
 63→    const table = entityRecord.table.name;
 64→    const now = new Date();
 65→
 66→    if (body.action === "confirm" && table === "decision") {
 67→      const [decisionRows] = await deps.surreal
 68→        .query<[Array<{ summary: string }>]>(
 69→          "SELECT summary FROM $record LIMIT 1;",
 70→          { record: entityRecord },
 71→        )
 72→        .collect<[Array<{ summary: string }>]>();
 73→      const decisionSummary = decisionRows[0]?.summary ?? entityId;
 74→
 75→      await confirmDecisionRecord({
 76→        surreal: deps.surreal,
 77→        decisionRecord: entityRecord as RecordId<"decision", string>,
 78→        confirmedAt: now,
 79→        notes: body.notes,
 80→      });
 81→
 82→      void fireDescriptionUpdates({
 83→        surreal: deps.surreal,
 84→        extractionModel: deps.extractionModel,
 85→        trigger: {
 86→          kind: "decision_confirmed",
 87→          entity: entityRecord,
 88→          summary: `Decision confirmed: ${decisionSummary}`,
 89→        },
 90→      }).catch(() => undefined);
 91→
 92→      logInfo("entity.action.confirm", "Decision confirmed", { workspaceId, entityId });
 93→      return jsonResponse({ status: "confirmed" }, 200);
 94→    }
 95→
 96→    if (body.action === "override" && table === "decision") {
 97→      if (!body.newSummary) {
 98→        return jsonError("newSummary is required for override action", 400);
 99→      }
100→      await deps.surreal.update(entityRecord as RecordId<"decision", string>).merge({
101→        summary: body.newSummary,
102→        status: "overridden",
103→        updated_at: now,
104→        ...(body.notes ? { override_notes: body.notes } : {}),
105→      });
106→      logInfo("entity.action.override", "Decision overridden", { workspaceId, entityId });
107→      return jsonResponse({ status: "overridden" }, 200);
108→    }
109→
110→    if (body.action === "complete" && table === "feature") {
111→      const [featureRows] = await deps.surreal
112→        .query<[Array<{ name: string }>]>(
113→          "SELECT name FROM $record LIMIT 1;",
114→          { record: entityRecord },
115→        )
116→        .collect<[Array<{ name: string }>]>();
117→      const featureName = featureRows[0]?.name ?? entityId;
118→
119→      await deps.surreal.update(entityRecord as RecordId<"feature", string>).merge({
120→        status: "done",
121→        updated_at: now,
122→      });
123→
124→      void fireDescriptionUpdates({
125→        surreal: deps.surreal,
126→        extractionModel: deps.extractionModel,
127→        trigger: {
128→          kind: "feature_completed",
129→          entity: entityRecord,
130→          summary: `Feature completed: ${featureName}`,
131→        },
132→      }).catch(() => undefined);
133→
134→      logInfo("entity.action.complete", "Feature completed", { workspaceId, entityId });
135→      return jsonResponse({ status: "completed" }, 200);
136→    }
137→
138→    if (body.action === "complete" && table === "task") {
139→      const [taskRows] = await deps.surreal
140→        .query<[Array<{ title: string }>]>(
141→          "SELECT title FROM $record LIMIT 1;",
142→          { record: entityRecord },
143→        )
144→        .collect<[Array<{ title: string }>]>();
145→      const taskTitle = taskRows[0]?.title ?? entityId;
146→
147→      await deps.surreal.update(entityRecord as RecordId<"task", string>).merge({
148→        status: "done",
149→        completed_at: now,
150→        updated_at: now,
151→      });
152→
153→      void fireDescriptionUpdates({
154→        surreal: deps.surreal,
155→        extractionModel: deps.extractionModel,
156→        trigger: {
157→          kind: "task_completed",
158→          entity: entityRecord,
159→          summary: `Task completed: ${taskTitle}`,
160→        },
161→      }).catch(() => undefined);
162→
163→      logInfo("entity.action.complete", "Task completed", { workspaceId, entityId });
164→      return jsonResponse({ status: "completed" }, 200);
165→    }
166→
167→    if (body.action === "set_priority" && (table === "task" || table === "decision" || table === "question")) {
168→      if (!body.priority || !(ENTITY_PRIORITIES as readonly string[]).includes(body.priority)) {
169→        return jsonError("priority must be one of: low, medium, high, critical", 400);
170→      }
171→      await deps.surreal.update(entityRecord).merge({
172→        priority: body.priority,
173→        updated_at: now,
174→      });
175→      logInfo("entity.action.set_priority", "Priority updated", { workspaceId, entityId, priority: body.priority });
176→      return jsonResponse({ status: "priority_updated", priority: body.priority }, 200);
177→    }
178→
179→    return jsonError(`action '${body.action}' is not valid for entity type '${table}'`, 400);
180→  } catch (error) {
181→    logError("entity.action.failed", "Entity action failed", error, {
182→      workspaceId,
183→      entityId,
184→      action: body.action,
185→    });
186→    const message = error instanceof Error ? error.message : "entity action failed";
187→    return jsonError(message, 500);
188→  }
189→}
