 4→export type PersonAttributionPatch =
 5→  | { kind: "feature"; field: "owner"; value: string }
 6→  | { kind: "feature"; field: "owner_name"; value: string }
 7→  | { kind: "task"; field: "owner"; value: string }
 8→  | { kind: "task"; field: "owner_name"; value: string }
 9→  | { kind: "decision"; field: "decided_by"; value: string }
10→  | { kind: "decision"; field: "decided_by_name"; value: string }
11→  | { kind: "question"; field: "assigned_to"; value: string }
12→  | { kind: "question"; field: "assigned_to_name"; value: string };
13→
14→export async function findWorkspacePersonByName(input: {
15→  surreal: Surreal;
16→  workspaceRecord: RecordId<"workspace", string>;
17→  personName: string;
18→}): Promise<RecordId<"person", string> | undefined> {
19→  const normalizedName = input.personName.trim();
20→  if (normalizedName.length === 0) {
21→    return undefined;
22→  }
23→
24→  const [rows] = await input.surreal
25→    .query<[Array<{ id: RecordId<"person", string> }>]>(
26→      [
27→        "SELECT id",
28→        "FROM person",
29→        "WHERE id IN (SELECT VALUE `in` FROM member_of WHERE out = $workspace)",
30→        "AND string::lowercase(name) = string::lowercase($name)",
31→        "LIMIT 1;",
32→      ].join(" "),
33→      {
34→        workspace: input.workspaceRecord,
35→        name: normalizedName,
36→      },
37→    )
38→    .collect<[Array<{ id: RecordId<"person", string> }>]>() ;
39→
40→  return rows[0]?.id;
41→}
42→
43→export function resolvePersonAttributionPatch(input: {
44→  targetKind: PersistableExtractableEntityKind;
45→  assigneeName: string;
46→  personRecordId?: string;
47→}): PersonAttributionPatch {
48→  if (input.targetKind === "feature") {
49→    if (input.personRecordId) {
50→      return { kind: "feature", field: "owner", value: input.personRecordId };
51→    }
52→
53→    return { kind: "feature", field: "owner_name", value: input.assigneeName };
54→  }
55→
56→  if (input.targetKind === "task") {
57→    if (input.personRecordId) {
58→      return { kind: "task", field: "owner", value: input.personRecordId };
59→    }
60→
61→    return { kind: "task", field: "owner_name", value: input.assigneeName };
62→  }
63→
64→  if (input.targetKind === "decision") {
65→    if (input.personRecordId) {
66→      return { kind: "decision", field: "decided_by", value: input.personRecordId };
67→    }
68→
69→    return { kind: "decision", field: "decided_by_name", value: input.assigneeName };
70→  }
71→
72→  if (input.personRecordId) {
73→    return { kind: "question", field: "assigned_to", value: input.personRecordId };
74→  }
75→
76→  return { kind: "question", field: "assigned_to_name", value: input.assigneeName };
77→}
