 80→function formatExtractionConversationHistory(rows: MessageContextRow[]): string {
 81→  if (rows.length === 0) {
 82→    return "(no prior messages)";
 83→  }
 84→
 85→  return rows.map((row) => `[message:${row.id.id as string}] ${row.role.toUpperCase()}: ${row.text}`).join("\n");
 86→}
 87→
 88→function formatExtractionCurrentMessage(currentMessage: MessageContextRow | undefined, sourceText: string): string {
 89→  if (!currentMessage) {
 90→    return `(no message metadata; source text: ${sourceText})`;
 91→  }
 92→
 93→  return `[message:${currentMessage.id.id as string}] ${currentMessage.role.toUpperCase()}: ${currentMessage.text}`;
 94→}
 95→
 96→function formatExtractionGraphContext(rows: ExtractionGraphContextRow[]): string {
 97→  if (rows.length === 0) {
 98→    return "(no prior extracted entities)";
 99→  }
100→
101→  return rows
102→    .map((row) => {
103→      const table = row.id.tb;
104→      return `[entity:${table}:${row.id.id as string}] ${row.kind}: ${row.text} (confidence ${row.confidence.toFixed(2)}, source message ${row.sourceMessage.id as string})`;
105→    })
106→    .join("\n");
107→}
