 25→export async function persistExtractionOutput(input: {
 26→  surreal: Surreal;
 27→  extractionModel: any;
 28→  embeddingModel: any;
 29→  embeddingDimension: number;
 30→  extractionModelId: string;
 31→  extractionStoreThreshold: number;
 32→  workspaceRecord: RecordId<"workspace", string>;
 33→  sourceRecord: SourceRecord;
 34→  sourceKind: SourceKind;
 35→  sourceLabel?: string;
 36→  promptText: string;
 37→  output: ExtractionPromptOutput;
 38→  sourceMessageRecord?: RecordId<"message", string>;
 39→  sourceChunkRecord?: RecordId<"document_chunk", string>;
 40→  extractionHistoryMessageIds?: string[];
 41→  now: Date;
 42→}): Promise<PersistExtractionResult> {
 43→  const startedAt = performance.now();
 44→  logInfo("extraction.persist.started", "Extraction persistence started", {
 45→    workspaceId: input.workspaceRecord.id as string,
 46→    sourceKind: input.sourceKind,
 47→    sourceId: input.sourceRecord.id as string,
 48→    candidateEntityCount: input.output.entities.length,
 49→    candidateRelationshipCount: input.output.relationships.length,
 50→  });
 51→
 52→  try {
 53→    const entities = postValidateEntities({
 54→      entities: input.output.entities,
 55→      sourceText: input.promptText,
 56→      storeThreshold: input.extractionStoreThreshold,
 57→    });
 58→    if (input.sourceKind === "message" && !input.sourceMessageRecord) {
 59→      throw new Error("message extraction persistence requires sourceMessageRecord");
 60→    }
 61→
 62→    const extractionHistoryMessageIds = new Set(input.extractionHistoryMessageIds ?? []);
 63→    const relationships = postValidateRelationships({
 64→      relationships: input.output.relationships,
 65→      storeThreshold: input.extractionStoreThreshold,
 66→    }).map((relationship) => ({
 67→      ...relationship,
 68→      kind: normalizeRelationshipKind(relationship.kind),
 69→    }));
 70→
 71→    const persistedEntities: ExtractedEntity[] = [];
 72→    const persistedRelationships: ExtractedRelationship[] = [];
 73→    const seeds: OnboardingSeedItem[] = [];
 74→    const embeddingTargets: Array<{ record: GraphEntityRecord; text: string }> = [];
 75→    const entityByTempId = new Map<string, TempEntityReference>();
 76→    const unresolvedAssigneeNames = new Set<string>();
 77→
 78→    const workspaceProjects = await loadWorkspaceProjects(input.surreal, input.workspaceRecord);
 79→
 80→    for (const extracted of entities) {
 81→      const resolvedFromMessageId = resolveValidatedResolvedFromMessageId({
 82→        resolvedFromMessageId: "resolvedFromMessageId" in extracted ? extracted.resolvedFromMessageId : undefined,
 83→        sourceKind: input.sourceKind,
 84→        sourceMessageId: input.sourceMessageRecord?.id as string | undefined,
 85→        extractionHistoryMessageIds,
 86→      });
 87→      const resolvedFromMessageRecord = resolvedFromMessageId
 88→        ? new RecordId("message", resolvedFromMessageId)
 89→        : undefined;
 90→
 91→      const persisted = await upsertGraphEntity({
 92→        surreal: input.surreal,
 93→        embeddingModel: input.embeddingModel,
 94→        embeddingDimension: input.embeddingDimension,
 95→        extractionModelId: input.extractionModelId,
 96→        workspaceRecord: input.workspaceRecord,
 97→        workspaceProjects,
 98→        sourceRecord: input.sourceRecord,
 99→        sourceKind: input.sourceKind,
100→        promptText: input.promptText,
101→        extracted: extracted as ExtractionPromptEntity & { kind: Exclude<EntityKind, "workspace" | "person" | "observation"> },
102→        sourceMessageRecord: input.sourceMessageRecord,
103→        sourceChunkRecord: input.sourceChunkRecord,
104→        resolvedFromMessageRecord,
105→        now: input.now,
106→      });
107→
108→      entityByTempId.set(extracted.tempId, {
109→        record: persisted.record,
110→        text: persisted.text,
111→        id: persisted.record.id as string,
112→        kind: persisted.kind,
113→      });
114→
115→      const extractedCategory = "category" in extracted ? extracted.category : undefined;
116→      const extractedPriority = "priority" in extracted ? extracted.priority : undefined;
117→
118→      persistedEntities.push({
119→        id: persisted.record.id as string,
120→        kind: persisted.kind,
121→        text: persisted.text,
122→        confidence: extracted.confidence,
123→        sourceKind: input.sourceKind,
124→        sourceId: input.sourceRecord.id as string,
125→        ...(extractedCategory ? { category: extractedCategory } : {}),
126→        ...(extractedPriority ? { priority: extractedPriority } : {}),
127→      });
128→
129→      seeds.push({
130→        id: persisted.record.id as string,
131→        kind: persisted.kind,
132→        text: persisted.text,
133→        confidence: extracted.confidence,
134→        sourceKind: input.sourceKind,
135→        sourceId: input.sourceRecord.id as string,
136→        ...(input.sourceLabel ? { sourceLabel: input.sourceLabel } : {}),
137→        ...(extractedCategory ? { category: extractedCategory } : {}),
138→      });
139→
140→      if (persisted.created) {
141→        embeddingTargets.push({
142→          record: persisted.record,
143→          text: persisted.text,
144→        });
145→
146→        const descriptionTargets: DescriptionTarget[] = ["project", "feature", "task"];
147→        if (descriptionTargets.includes(persisted.kind as DescriptionTarget)) {
148→          void seedDescriptionEntry({
149→            surreal: input.surreal,
150→            targetRecord: persisted.record,
151→            text: extracted.evidence,
152→            reasoning: "Extracted from conversation",
153→            triggeredBy: input.sourceMessageRecord ? [input.sourceMessageRecord] : [],
154→          }).catch(() => undefined);
155→        }
156→
157→        if (persisted.kind === "feature") {
158→          void fireDescriptionUpdates({
159→            surreal: input.surreal,
160→            extractionModel: input.extractionModel,
161→            trigger: {
162→              kind: "feature_created",
163→              entity: persisted.record,
164→              summary: `Feature added: ${persisted.text}`,
165→            },
166→          }).catch(() => undefined);
167→        }
168→      }
169→
170→      const assigneeName = "assignee_name" in extracted ? extracted.assignee_name : undefined;
171→      if (assigneeName) {
172→        const attribution = await applyAssigneeReference({
173→          surreal: input.surreal,
174→          workspaceRecord: input.workspaceRecord,
175→          entityRecord: persisted.record,
176→          entityKind: persisted.kind,
177→          assigneeName,
178→          now: input.now,
179→        });
180→
181→        if (!attribution.resolved) {
182→          unresolvedAssigneeNames.add(attribution.assigneeName);
183→        }
184→      }
185→    }
186→
187→    for (const relationship of relationships) {
188→      const from = entityByTempId.get(relationship.fromTempId);
189→      const to = entityByTempId.get(relationship.toTempId);
190→      if (!from || !to) {
191→        continue;
192→      }
193→
194→      const relationRecord = new RecordId("entity_relation", randomUUID());
195→      await input.surreal.relate(from.record, relationRecord, to.record, {
196→        kind: relationship.kind,
197→        confidence: relationship.confidence,
198→        ...(input.sourceMessageRecord ? { source_message: input.sourceMessageRecord } : {}),
199→        ...(input.sourceChunkRecord ? { source_chunk: input.sourceChunkRecord } : {}),
200→        extracted_at: input.now,
201→        created_at: input.now,
202→        from_text: relationship.fromText,
203→        to_text: relationship.toText,
204→      }).output("after");
205→
206→      persistedRelationships.push({
207→        id: relationRecord.id as string,
208→        kind: relationship.kind,
209→        fromId: from.id,
210→        toId: to.id,
211→        confidence: relationship.confidence,
212→        sourceKind: input.sourceKind,
213→        sourceId: input.sourceRecord.id as string,
214→        ...(input.sourceMessageRecord ? { sourceMessageId: input.sourceMessageRecord.id as string } : {}),
215→        fromText: relationship.fromText,
216→        toText: relationship.toText,
217→      });
218→    }
219→
220→    logInfo("extraction.persist.completed", "Extraction persistence completed", {
221→      workspaceId: input.workspaceRecord.id as string,
222→      sourceKind: input.sourceKind,
223→      sourceId: input.sourceRecord.id as string,
224→      persistedEntityCount: persistedEntities.length,
225→      persistedRelationshipCount: persistedRelationships.length,
226→      seedCount: seeds.length,
227→      toolCount: input.output.tools.length,
228→      unresolvedAssigneeCount: unresolvedAssigneeNames.size,
229→      durationMs: elapsedMs(startedAt),
230→    });
231→
232→    return {
233→      entities: persistedEntities,
234→      relationships: persistedRelationships,
235→      seeds,
236→      embeddingTargets,
237→      tools: input.output.tools.map((tool) => tool.trim()).filter((tool) => tool.length > 0),
238→      unresolvedAssigneeNames: [...unresolvedAssigneeNames],
239→    };
240→  } catch (error) {
241→    logError("extraction.persist.failed", "Extraction persistence failed", error, {
242→      workspaceId: input.workspaceRecord.id as string,
243→      sourceKind: input.sourceKind,
244→      sourceId: input.sourceRecord.id as string,
245→      durationMs: elapsedMs(startedAt),
246→    });
247→    throw error;
248→  }
249→}
