232→export async function createProvenanceEdge(input: {
233→  surreal: Surreal;
234→  sourceRecord: SourceRecord;
235→  targetRecord: GraphEntityRecord;
236→  confidence: number;
237→  model: string;
238→  now: Date;
239→  fromText: string;
240→  evidence: string;
241→  evidenceSourceRecord?: RecordId<"message", string>;
242→  resolvedFromRecord?: RecordId<"message", string>;
243→}): Promise<void> {
244→  await input.surreal.relate(input.sourceRecord, new RecordId("extraction_relation", randomUUID()), input.targetRecord, {
245→    confidence: input.confidence,
246→    extracted_at: input.now,
247→    created_at: input.now,
248→    model: input.model,
249→    from_text: input.fromText,
250→    evidence: input.evidence,
251→    ...(input.evidenceSourceRecord ? { evidence_source: input.evidenceSourceRecord } : {}),
252→    ...(input.resolvedFromRecord ? { resolved_from: input.resolvedFromRecord } : {}),
