256→function buildEntityRecordContent(
257→  kind: PersistableExtractableEntityKind,
258→  text: string,
259→  confidence: number,
260→  now: Date,
261→  embedding?: number[],
262→  sourceMessageRecord?: RecordId<"message", string>,
263→  category?: string,
264→  priority?: string,
265→): Record<string, unknown> {
266→  if (kind === "project") {
267→    return {
268→      name: text,
269→      status: "active",
270→      ...(embedding ? { embedding } : {}),
271→      created_at: now,
272→      updated_at: now,
273→    };
274→  }
275→
276→  if (kind === "feature") {
277→    return {
278→      name: text,
279→      status: "active",
280→      ...(embedding ? { embedding } : {}),
281→      created_at: now,
282→      updated_at: now,
283→    };
284→  }
285→
286→  if (kind === "task") {
287→    return {
288→      title: text,
289→      status: "open",
290→      extraction_confidence: confidence,
291→      extracted_at: now,
292→      ...(sourceMessageRecord ? { source_message: sourceMessageRecord } : {}),
293→      ...(embedding ? { embedding } : {}),
294→      ...(category ? { category } : {}),
295→      ...(priority ? { priority } : {}),
296→      created_at: now,
297→      updated_at: now,
298→    };
299→  }
300→
301→  if (kind === "decision") {
302→    return {
303→      summary: text,
304→      status: "extracted",
305→      extraction_confidence: confidence,
306→      extracted_at: now,
307→      ...(sourceMessageRecord ? { source_message: sourceMessageRecord } : {}),
308→      ...(embedding ? { embedding } : {}),
309→      ...(category ? { category } : {}),
310→      ...(priority ? { priority } : {}),
311→      created_at: now,
312→      updated_at: now,
313→    };
314→  }
315→
316→  // question (fallthrough)
317→  return {
318→    text,
319→    status: "open",
320→    extraction_confidence: confidence,
321→    extracted_at: now,
322→    ...(sourceMessageRecord ? { source_message: sourceMessageRecord } : {}),
323→    ...(embedding ? { embedding } : {}),
324→    ...(category ? { category } : {}),
325→    ...(priority ? { priority } : {}),
326→    created_at: now,
327→    updated_at: now,
328→  };
329→}
