331→export async function loadWorkspaceKindCandidates(
332→  surreal: Surreal,
333→  workspaceRecord: RecordId<"workspace", string>,
334→  kind: ExtractableEntityKind,
335→): Promise<CandidateEntityRow[]> {
336→  if (kind === "project") {
337→    const [rows] = await surreal
338→      .query<[CandidateEntityRow[]]>(
339→        "SELECT id, name AS text, embedding FROM project WHERE id IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace);",
340→        { workspace: workspaceRecord },
341→      )
342→      .collect<[CandidateEntityRow[]]>();
343→    return rows;
344→  }
345→
346→  if (kind === "person") {
347→    const [rows] = await surreal
348→      .query<[CandidateEntityRow[]]>(
349→        "SELECT id, name AS text, embedding FROM person WHERE id IN (SELECT VALUE `in` FROM member_of WHERE out = $workspace);",
350→        { workspace: workspaceRecord },
351→      )
352→      .collect<[CandidateEntityRow[]]>();
353→    return rows;
354→  }
355→
356→  if (kind === "feature") {
357→    const [rows] = await surreal
358→      .query<[CandidateEntityRow[]]>(
359→        [
360→          "SELECT id, name AS text, embedding",
361→          "FROM feature",
362→          "WHERE id IN (",
363→          "  SELECT VALUE out",
364→          "  FROM has_feature",
365→          "  WHERE `in` IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace)",
366→          ");",
367→        ].join(" "),
368→        { workspace: workspaceRecord },
369→      )
370→      .collect<[CandidateEntityRow[]]>();
371→    return rows;
372→  }
373→
374→  if (kind === "task") {
375→    const [rows] = await surreal
376→      .query<[CandidateEntityRow[]]>(
377→        [
378→          "SELECT id, title AS text, embedding",
379→          "FROM task",
380→          "WHERE id IN (",
381→          "  SELECT VALUE `in`",
382→          "  FROM belongs_to",
383→          "  WHERE out IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace)",
384→          ")",
385→          "OR source_message IN (",
386→          "  SELECT VALUE id",
387→          "  FROM message",
388→          "  WHERE conversation IN (SELECT VALUE id FROM conversation WHERE workspace = $workspace)",
389→          ");",
390→        ].join(" "),
391→        { workspace: workspaceRecord },
392→      )
393→      .collect<[CandidateEntityRow[]]>();
394→    return uniqueCandidateRows(rows);
395→  }
396→
397→  if (kind === "decision") {
398→    const [rows] = await surreal
399→      .query<[CandidateEntityRow[]]>(
400→        [
401→          "SELECT id, summary AS text, embedding",
402→          "FROM decision",
403→          "WHERE id IN (",
404→          "  SELECT VALUE `in`",
405→          "  FROM belongs_to",
406→          "  WHERE out IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace)",
407→          ")",
408→          "OR source_message IN (",
409→          "  SELECT VALUE id",
410→          "  FROM message",
411→          "  WHERE conversation IN (SELECT VALUE id FROM conversation WHERE workspace = $workspace)",
412→          ");",
413→        ].join(" "),
414→        { workspace: workspaceRecord },
415→      )
416→      .collect<[CandidateEntityRow[]]>();
417→    return uniqueCandidateRows(rows);
418→  }
419→
420→  const [rows] = await surreal
421→    .query<[CandidateEntityRow[]]>(
422→      [
423→        "SELECT id, text AS text, embedding",
424→        "FROM question",
425→        "WHERE id IN (",
426→        "  SELECT VALUE `in`",
427→        "  FROM belongs_to",
428→        "  WHERE out IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace)",
429→        ")",
430→        "OR source_message IN (",
431→        "  SELECT VALUE id",
432→        "  FROM message",
433→        "  WHERE conversation IN (SELECT VALUE id FROM conversation WHERE workspace = $workspace)",
434→        ");",
435→      ].join(" "),
436→      { workspace: workspaceRecord },
437→    )
438→    .collect<[CandidateEntityRow[]]>();
439→  return uniqueCandidateRows(rows);
440→}
441→
442→function uniqueCandidateRows(rows: CandidateEntityRow[]): CandidateEntityRow[] {
443→  const byId = new Map<string, CandidateEntityRow>();
444→  for (const row of rows) {
445→    byId.set(row.id.id as string, row);
446→  }
447→  return [...byId.values()];
448→}
