450→export async function appendWorkspaceTools(
451→  surreal: Surreal,
452→  workspaceRecord: RecordId<"workspace", string>,
453→  toolsToAdd: string[],
454→  now: Date,
455→): Promise<void> {
456→  const [rows] = await surreal
457→    .query<[Array<{ tools?: string[] }>]>("SELECT tools FROM $workspace LIMIT 1;", {
458→      workspace: workspaceRecord,
459→    })
460→    .collect<[Array<{ tools?: string[] }>]>();
461→
462→  const existingTools = rows[0]?.tools ?? [];
463→  const merged = [...new Set([...existingTools, ...toolsToAdd])];
464→  await surreal.update(workspaceRecord).merge({
465→    tools: merged,
466→    updated_at: now,
467→  });
468→}
