 10→export type ServerConfig = {
 11→  openRouterApiKey: string;
 12→  assistantModelId: string;
 13→  extractionModelId: string;
 14→  pmModelId: string;
 15→  embeddingModelId: string;
 16→  embeddingDimension: number;
 17→  extractionStoreThreshold: number;
 18→  extractionDisplayThreshold: number;
 19→  openRouterReasoning?: OpenRouterReasoningOptions;
 20→  surrealUrl: string;
 21→  surrealUsername: string;
 22→  surrealPassword: string;
 23→  surrealNamespace: string;
 24→  surrealDatabase: string;
 25→  port: number;
 26→};
 27→
 28→export function loadServerConfig(): ServerConfig {
 29→  const openRouterApiKey = requireEnv("OPENROUTER_API_KEY");
 30→
 31→  const extractionStoreThreshold = parseUnitInterval(
 32→    requireEnv("EXTRACTION_STORE_THRESHOLD"),
 33→    "EXTRACTION_STORE_THRESHOLD",
 34→  );
 35→
 36→  const extractionDisplayThreshold = parseUnitInterval(
 37→    requireEnv("EXTRACTION_DISPLAY_THRESHOLD"),
 38→    "EXTRACTION_DISPLAY_THRESHOLD",
 39→  );
 40→
 41→  if (extractionDisplayThreshold < extractionStoreThreshold) {
 42→    throw new Error("EXTRACTION_DISPLAY_THRESHOLD must be greater than or equal to EXTRACTION_STORE_THRESHOLD");
 43→  }
 44→
 45→  const assistantModelId = requireEnv("ASSISTANT_MODEL");
 46→  const extractionModelId = requireEnv("EXTRACTION_MODEL");
 47→  const pmModelId = Bun.env.PM_MODEL && Bun.env.PM_MODEL.trim().length > 0
 48→    ? Bun.env.PM_MODEL.trim()
 49→    : extractionModelId;
 50→  const embeddingModelId = requireEnv("OPENROUTER_EMBEDDING_MODEL");
 51→  const embeddingDimension = parsePositiveInteger(requireEnv("EMBEDDING_DIMENSION"), "EMBEDDING_DIMENSION");
 52→
 53→  const surrealUrl = requireEnv("SURREAL_URL");
 54→  const surrealUsername = requireEnv("SURREAL_USERNAME");
 55→  const surrealPassword = requireEnv("SURREAL_PASSWORD");
 56→  const surrealNamespace = requireEnv("SURREAL_NAMESPACE");
 57→  const surrealDatabase = requireEnv("SURREAL_DATABASE");
 58→
 59→  const port = parsePositiveInteger(requireEnv("PORT"), "PORT");
 60→
 61→  return {
 62→    openRouterApiKey,
 63→    assistantModelId,
 64→    extractionModelId,
 65→    pmModelId,
 66→    embeddingModelId,
 67→    embeddingDimension,
 68→    extractionStoreThreshold,
 69→    extractionDisplayThreshold,
 70→    openRouterReasoning: parseOpenRouterReasoning(),
 71→    surrealUrl,
 72→    surrealUsername,
 73→    surrealPassword,
 74→    surrealNamespace,
 75→    surrealDatabase,
 76→    port,
 77→  };
 78→}
 79→
 80→function requireEnv(name: string): string {
 81→  const value = Bun.env[name];
 82→  if (!value || value.trim().length === 0) {
 83→    throw new Error(`${name} is required`);
 84→  }
 85→
 86→  return value;
 87→}
 88→
 89→function parsePositiveInteger(value: string, envName: string): number {
 90→  const parsed = Number(value);
 91→  if (!Number.isInteger(parsed) || parsed < 1) {
 92→    throw new Error(`${envName} must be a positive integer`);
 93→  }
 94→  return parsed;
 95→}
 96→
 97→function parseUnitInterval(value: string, envName: string): number {
 98→  const parsed = Number(value);
 99→  if (!Number.isFinite(parsed) || parsed < 0 || parsed > 1) {
100→    throw new Error(`${envName} must be a number between 0 and 1`);
101→  }
102→
103→  return parsed;
104→}
105→
106→function parseOpenRouterReasoning(): OpenRouterReasoningOptions | undefined {
107→  const effortValue = Bun.env.OPENROUTER_REASONING_EFFORT;
108→  const maxTokensValue = Bun.env.OPENROUTER_REASONING_MAX_TOKENS;
109→
110→  if (!effortValue && !maxTokensValue) {
111→    return undefined;
112→  }
113→
114→  const reasoning: OpenRouterReasoningOptions = {};
115→
116→  if (effortValue) {
117→    const allowedEfforts: OpenRouterReasoningEffort[] = ["xhigh", "high", "medium", "low", "minimal", "none"];
118→
119→    if (!allowedEfforts.includes(effortValue as OpenRouterReasoningEffort)) {
120→      throw new Error("OPENROUTER_REASONING_EFFORT must be one of xhigh, high, medium, low, minimal, none");
121→    }
122→    reasoning.effort = effortValue as OpenRouterReasoningEffort;
123→  }
124→
125→  if (maxTokensValue) {
126→    const parsed = Number(maxTokensValue);
127→    if (!Number.isFinite(parsed) || parsed < 1) {
128→      throw new Error("OPENROUTER_REASONING_MAX_TOKENS must be a positive number");
129→    }
130→    reasoning.max_tokens = parsed;
131→  }
132→
133→  return reasoning;
134→}
