378→    });
379→    seen.add(entityKey);
380→  }
381→
382→  // Merge inherited entities from parent conversation when branch has sparse context
383→  if (input.inheritedEntityIds && input.inheritedEntityIds.length > 0 && items.length < 5) {
384→    const [inheritedRows] = await input.surreal
385→      .query<[Array<{ in: RecordId<"message", string>; out: GraphEntityRecord; confidence: number; extracted_at: string | Date }>]>(
386→        [
387→          "SELECT `in`, out, confidence, extracted_at",
388→          "FROM extraction_relation",
389→          "WHERE out IN $entityIds",
390→          "ORDER BY extracted_at DESC",
391→          "LIMIT $limit;",
392→        ].join(" "),
393→        { entityIds: input.inheritedEntityIds, limit: input.limit },
394→      )
395→      .collect<[Array<{ in: RecordId<"message", string>; out: GraphEntityRecord; confidence: number; extracted_at: string | Date }>]>();
396→
397→    for (const row of inheritedRows) {
398→      const table = row.out.table.name as GraphEntityTable;
399→      if (
400→        table !== "workspace" &&
401→        table !== "project" &&
402→        table !== "person" &&
403→        table !== "feature" &&
404→        table !== "task" &&
405→        table !== "decision" &&
406→        table !== "question"
407→      ) {
408→        continue;
409→      }
410→
411→      const entityKey = `${table}:${toRecordIdString(row.out)}`;
412→      if (seen.has(entityKey)) continue;
413→
414→      const name = await readEntityName(input.surreal, row.out);
415→      if (!name) continue;
416→
417→      items.push({
418→        id: toRecordIdString(row.out),
419→        kind: table,
420→        name,
421→        confidence: row.confidence,
422→        sourceMessageId: toRecordIdString(row.in),
423→      });
424→      seen.add(entityKey);
425→    }
426→  }
427→
428→  return items;
