  1→import type { CreateWorkspaceRequest, OnboardingAction } from "../../shared/contracts";
  2→import { HttpError } from "./errors";
  3→
  4→const MAX_UPLOAD_BYTES = 2 * 1024 * 1024;
  5→const allowedUploadExtensions = new Set(["md", "txt"]);
