 14→export type ParsedIncomingMessage = {
 15→  clientMessageId: string;
 16→  workspaceId: string;
 17→  conversationId?: string;
 18→  text: string;
 19→  onboardingAction?: OnboardingAction;
 20→  attachment?: IncomingAttachment;
 21→};
 22→
 23→const onboardingActions = new Set(["finalize_onboarding", "continue_onboarding"]);
