 976→        confidence: number;
 977→        extracted_at: string | Date;
 978→        evidence?: string;
 979→        evidence_source?: RecordId<"message", string>;
 980→        resolved_from?: RecordId<"message", string>;
 981→        from_text?: string;
 982→      }>,
 983→    ]>(
