19→async function handleEntityDetail(
20→  deps: ServerDependencies,
21→  entityId: string,
22→  url: URL,
23→): Promise<Response> {
24→  const workspaceId = url.searchParams.get("workspaceId")?.trim();
25→  if (!workspaceId) {
26→    return jsonError("workspaceId is required", 400);
27→  }
28→
29→  let workspaceRecord;
30→  try {
31→    workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
32→  } catch (error) {
33→    if (error instanceof HttpError) {
34→      return jsonError(error.message, error.status);
35→    }
36→    logError("entity.detail.workspace_resolve.failed", "Failed to resolve workspace", error, { workspaceId });
37→    return jsonError("failed to resolve workspace", 500);
38→  }
39→
40→  try {
41→    const entityTables: GraphEntityTable[] = ["workspace", "project", "person", "feature", "task", "decision", "question"];
42→    const entityRecord = parseRecordIdString(entityId, entityTables);
43→    const detail = await getEntityDetail({
44→      surreal: deps.surreal,
45→      workspaceRecord,
46→      entityRecord,
47→    });
48→
49→    const response: EntityDetailResponse = {
50→      entity: detail.entity,
51→      relationships: detail.relationships,
52→      provenance: detail.provenance,
53→    };
54→
55→    logInfo("entity.detail.served", "Entity detail served", {
56→      workspaceId,
57→      entityId,
58→      relationshipCount: detail.relationships.length,
59→      provenanceCount: detail.provenance.length,
60→    });
61→
62→    return jsonResponse(response, 200);
63→  } catch (error) {
64→    logError("entity.detail.failed", "Entity detail failed", error, {
65→      workspaceId,
66→      entityId,
67→    });
68→    const message = error instanceof Error ? error.message : "entity detail failed";
69→    return jsonError(message, 500);
70→  }
71→}
