 53→export async function ensureWorkspaceProjectEdge(
 54→  surreal: Surreal,
 55→  workspaceRecord: RecordId<"workspace", string>,
 56→  projectRecord: RecordId<"project", string>,
 57→  now: Date,
 58→): Promise<void> {
