338→DEFINE FUNCTION fn::entity_search_workspace($q: string, $limit: int, $workspace: record<workspace>) {
339→  LET $query = string::lowercase(string::trim($q));
340→  LET $safe_limit = math::min([math::max([$limit, 1]), 100]);
341→  LET $workspace_conversations = SELECT VALUE id FROM conversation WHERE workspace = $workspace;
342→  LET $workspace_messages = SELECT VALUE id FROM message WHERE conversation IN $workspace_conversations;
343→
344→  LET $task_rows = SELECT
345→    id,
346→    "task" AS kind,
347→    title AS text,
348→    extraction_confidence AS confidence,
349→    source_message AS sourceMessage,
350→    priority,
351→    created_at
352→  FROM task
353→  WHERE source_message != NONE
354→    AND source_message IN $workspace_messages
355→    AND extraction_confidence != NONE
356→    AND string::contains(string::lowercase(title), $query)
357→  ORDER BY created_at DESC
358→  LIMIT $safe_limit;
359→
360→  LET $decision_rows = SELECT
361→    id,
362→    "decision" AS kind,
363→    summary AS text,
364→    extraction_confidence AS confidence,
365→    source_message AS sourceMessage,
366→    priority,
367→    created_at
368→  FROM decision
369→  WHERE source_message != NONE
370→    AND source_message IN $workspace_messages
371→    AND extraction_confidence != NONE
372→    AND string::contains(string::lowercase(summary), $query)
373→  ORDER BY created_at DESC
374→  LIMIT $safe_limit;
375→
376→  LET $question_rows = SELECT
377→    id,
378→    "question" AS kind,
379→    text AS text,
380→    extraction_confidence AS confidence,
381→    source_message AS sourceMessage,
382→    priority,
383→    created_at
384→  FROM question
385→  WHERE source_message != NONE
386→    AND source_message IN $workspace_messages
387→    AND extraction_confidence != NONE
388→    AND string::contains(string::lowercase(text), $query)
389→  ORDER BY created_at DESC
390→  LIMIT $safe_limit;
391→
392→  RETURN array::flatten([$task_rows, $decision_rows, $question_rows]);
393→};
394→
395→DEFINE FUNCTION fn::entity_search_project($q: string, $limit: int, $workspace: record<workspace>, $project: record<project>) {
396→  LET $query = string::lowercase(string::trim($q));
