398→  LET $workspace_conversations = SELECT VALUE id FROM conversation WHERE workspace = $workspace;
399→  LET $workspace_messages = SELECT VALUE id FROM message WHERE conversation IN $workspace_conversations;
400→  LET $project_entity_ids = SELECT VALUE `in` FROM belongs_to WHERE out = $project;
401→
402→  LET $task_rows = SELECT
403→    id,
404→    "task" AS kind,
405→    title AS text,
406→    extraction_confidence AS confidence,
407→    source_message AS sourceMessage,
408→    priority,
409→    created_at
410→  FROM task
411→  WHERE source_message != NONE
412→    AND source_message IN $workspace_messages
413→    AND extraction_confidence != NONE
414→    AND id IN $project_entity_ids
415→    AND string::contains(string::lowercase(title), $query)
416→  ORDER BY created_at DESC
417→  LIMIT $safe_limit;
418→
419→  LET $decision_rows = SELECT
420→    id,
