429→    AND source_message IN $workspace_messages
430→    AND extraction_confidence != NONE
431→    AND id IN $project_entity_ids
432→    AND string::contains(string::lowercase(summary), $query)
433→  ORDER BY created_at DESC
434→  LIMIT $safe_limit;
435→
436→  LET $question_rows = SELECT
437→    id,
438→    "question" AS kind,
439→    text AS text,
