  1→import { randomUUID } from "node:crypto";
  2→import { RecordId, type Surreal } from "surrealdb";
  3→import { isRicherEntityName } from "./dedup";
  4→import { isFuzzyNameMatch, normalizeName } from "./normalize";
  5→import type { ExtractionPromptEntity } from "./schema";
  6→import type {
  7→  CandidateEntityRow,
  8→  ExtractableEntityKind,
  9→  GraphEntityRecord,
 10→  PersistableExtractableEntityKind,
 11→  ProjectScopeRow,
 12→  SourceRecord,
 13→} from "./types";
 14→import { ensureProjectFeatureEdge, ensureWorkspaceProjectEdge, resolveEntityProject } from "../workspace/workspace-scope";
 15→import { createEmbedding } from "./embedding-writeback";
 16→
 17→export async function upsertGraphEntity(input: {
 18→  surreal: Surreal;
 19→  embeddingModel: any;
 20→  embeddingDimension: number;
 21→  extractionModelId: string;
 22→  workspaceRecord: RecordId<"workspace", string>;
 23→  workspaceProjects: ProjectScopeRow[];
 24→  sourceRecord: SourceRecord;
 25→  sourceKind: "message" | "document_chunk";
 26→  promptText: string;
 27→  extracted: ExtractionPromptEntity & { kind: PersistableExtractableEntityKind };
 28→  sourceMessageRecord?: RecordId<"message", string>;
 29→  sourceChunkRecord?: RecordId<"document_chunk", string>;
 30→  resolvedFromMessageRecord?: RecordId<"message", string>;
 31→  now: Date;
 32→}): Promise<{ record: GraphEntityRecord; text: string; kind: PersistableExtractableEntityKind; created: boolean }> {
 33→  const candidateEmbedding = await createEmbedding(input.embeddingModel, input.embeddingDimension, input.extracted.text);
 34→  const candidates = await loadWorkspaceKindCandidates(input.surreal, input.workspaceRecord, input.extracted.kind);
 35→  const normalizedExtractedText = normalizeName(input.extracted.text);
 36→
 37→  const exactNameCandidate = candidates.find((candidate) => normalizeName(candidate.text) === normalizedExtractedText);
 38→  if (exactNameCandidate) {
 39→    const mergedText = await maybeUpgradeMergedEntityName(
 40→      input.surreal,
 41→      input.extracted.kind,
 42→      input.extracted.text,
 43→      exactNameCandidate,
 44→      input.now,
 45→    );
 46→
 47→    await createProvenanceEdge({
 48→      surreal: input.surreal,
 49→      sourceRecord: input.sourceRecord,
 50→      targetRecord: exactNameCandidate.id,
 51→      confidence: input.extracted.confidence,
 52→      model: input.extractionModelId,
 53→      now: input.now,
 54→      fromText: input.extracted.text,
 55→      evidence: input.extracted.evidence,
 56→      evidenceSourceRecord: input.sourceMessageRecord,
 57→      resolvedFromRecord: input.resolvedFromMessageRecord,
 58→    });
 59→
 60→    return {
 61→      record: exactNameCandidate.id,
 62→      text: mergedText,
 63→      kind: input.extracted.kind,
 64→      created: false,
 65→    };
 66→  }
 67→
 68→  let bestCandidate: CandidateEntityRow | undefined;
 69→  let bestSimilarity = -1;
 70→
 71→  for (const candidate of candidates) {
 72→    if (!candidate.embedding || !candidateEmbedding) {
 73→      continue;
 74→    }
 75→
 76→    const similarity = cosineSimilarity(candidateEmbedding, candidate.embedding);
 77→    if (similarity > bestSimilarity) {
 78→      bestSimilarity = similarity;
 79→      bestCandidate = candidate;
 80→    }
 81→  }
 82→
 83→  const fuzzyMatch = bestCandidate
 84→    ? isFuzzyNameMatch(normalizeName(input.extracted.text), normalizeName(bestCandidate.text))
 85→    : false;
 86→
 87→  if (bestCandidate && bestSimilarity > 0.95 && fuzzyMatch) {
 88→    const mergedText = await maybeUpgradeMergedEntityName(
 89→      input.surreal,
 90→      input.extracted.kind,
 91→      input.extracted.text,
 92→      bestCandidate,
 93→      input.now,
 94→    );
 95→
 96→    await createProvenanceEdge({
 97→      surreal: input.surreal,
 98→      sourceRecord: input.sourceRecord,
 99→      targetRecord: bestCandidate.id,
100→      confidence: input.extracted.confidence,
101→      model: input.extractionModelId,
102→      now: input.now,
103→      fromText: input.extracted.text,
104→      evidence: input.extracted.evidence,
105→      evidenceSourceRecord: input.sourceMessageRecord,
106→      resolvedFromRecord: input.resolvedFromMessageRecord,
107→    });
108→
109→    return {
110→      record: bestCandidate.id,
111→      text: mergedText,
112→      kind: input.extracted.kind,
113→      created: false,
114→    };
115→  }
116→
117→  const entityRecord = new RecordId(input.extracted.kind, randomUUID()) as GraphEntityRecord;
118→  await input.surreal.create(entityRecord).content(
119→    buildEntityRecordContent(
120→      input.extracted.kind,
121→      input.extracted.text,
122→      input.extracted.confidence,
123→      input.now,
124→      candidateEmbedding,
125→      input.sourceMessageRecord,
126→      input.extracted.category,
127→      input.extracted.priority,
128→    ),
129→  );
130→
131→  await createProvenanceEdge({
132→    surreal: input.surreal,
133→    sourceRecord: input.sourceRecord,
134→    targetRecord: entityRecord,
135→    confidence: input.extracted.confidence,
136→    model: input.extractionModelId,
137→    now: input.now,
138→    fromText: input.extracted.text,
139→    evidence: input.extracted.evidence,
140→    evidenceSourceRecord: input.sourceMessageRecord,
141→    resolvedFromRecord: input.resolvedFromMessageRecord,
142→  });
143→
144→  if (input.extracted.kind === "project") {
145→    await ensureWorkspaceProjectEdge(input.surreal, input.workspaceRecord, entityRecord as RecordId<"project", string>, input.now);
146→    input.workspaceProjects.push({
147→      id: entityRecord as RecordId<"project", string>,
148→      name: input.extracted.text,
149→    });
150→  }
151→
152→  if (input.extracted.kind === "feature") {
153→    const projectRecord = resolveEntityProject(input.extracted.text, input.promptText, input.workspaceProjects);
154→    if (projectRecord) {
155→      await ensureProjectFeatureEdge(input.surreal, projectRecord, entityRecord as RecordId<"feature", string>, input.now);
156→    }
157→  }
158→
159→  if (input.extracted.kind === "task" || input.extracted.kind === "decision" || input.extracted.kind === "question") {
160→    const projectRecord = resolveEntityProject(input.extracted.text, input.promptText, input.workspaceProjects);
161→    if (projectRecord) {
162→      await input.surreal.relate(entityRecord, new RecordId("belongs_to", randomUUID()), projectRecord, {
163→        added_at: input.now,
164→      }).output("after");
165→    }
166→  }
167→
168→  if (bestCandidate && bestSimilarity >= 0.8 && bestSimilarity <= 0.95) {
169→    await input.surreal.relate(entityRecord, new RecordId("entity_relation", randomUUID()), bestCandidate.id, {
170→      kind: "POSSIBLE_DUPLICATE",
171→      confidence: bestSimilarity,
172→      ...(input.sourceMessageRecord ? { source_message: input.sourceMessageRecord } : {}),
173→      ...(input.sourceChunkRecord ? { source_chunk: input.sourceChunkRecord } : {}),
174→      extracted_at: input.now,
175→      created_at: input.now,
176→      from_text: input.extracted.text,
177→      to_text: bestCandidate.text,
178→    }).output("after");
179→  }
180→
181→  return {
182→    record: entityRecord,
183→    text: input.extracted.text,
184→    kind: input.extracted.kind,
185→    created: true,
186→  };
187→}
188→
189→export async function maybeUpgradeMergedEntityName(
190→  surreal: Surreal,
191→  kind: PersistableExtractableEntityKind,
192→  incomingText: string,
193→  candidate: CandidateEntityRow,
194→  now: Date,
195→): Promise<string> {
196→  if (!isRicherEntityName(incomingText, candidate.text)) {
197→    return candidate.text;
198→  }
199→
200→  if (kind === "project" || kind === "feature") {
201→    await surreal.update(candidate.id as RecordId<"project" | "feature", string>).merge({
202→      name: incomingText,
203→      updated_at: now,
204→    });
205→    return incomingText;
206→  }
207→
208→  if (kind === "task") {
209→    await surreal.update(candidate.id as RecordId<"task", string>).merge({
210→      title: incomingText,
211→      updated_at: now,
212→    });
213→    return incomingText;
214→  }
215→
216→  if (kind === "decision") {
217→    await surreal.update(candidate.id as RecordId<"decision", string>).merge({
218→      summary: incomingText,
219→      updated_at: now,
220→    });
221→    return incomingText;
222→  }
223→
224→  await surreal.update(candidate.id as RecordId<"question", string>).merge({
225→    text: incomingText,
226→    updated_at: now,
227→  });
228→
229→  return incomingText;
230→}
231→
232→export async function createProvenanceEdge(input: {
233→  surreal: Surreal;
234→  sourceRecord: SourceRecord;
235→  targetRecord: GraphEntityRecord;
236→  confidence: number;
237→  model: string;
238→  now: Date;
239→  fromText: string;
240→  evidence: string;
241→  evidenceSourceRecord?: RecordId<"message", string>;
242→  resolvedFromRecord?: RecordId<"message", string>;
243→}): Promise<void> {
244→  await input.surreal.relate(input.sourceRecord, new RecordId("extraction_relation", randomUUID()), input.targetRecord, {
245→    confidence: input.confidence,
246→    extracted_at: input.now,
247→    created_at: input.now,
248→    model: input.model,
249→    from_text: input.fromText,
250→    evidence: input.evidence,
251→    ...(input.evidenceSourceRecord ? { evidence_source: input.evidenceSourceRecord } : {}),
252→    ...(input.resolvedFromRecord ? { resolved_from: input.resolvedFromRecord } : {}),
253→  }).output("after");
254→}
255→
256→function buildEntityRecordContent(
257→  kind: PersistableExtractableEntityKind,
258→  text: string,
259→  confidence: number,
260→  now: Date,
261→  embedding?: number[],
262→  sourceMessageRecord?: RecordId<"message", string>,
263→  category?: string,
264→  priority?: string,
265→): Record<string, unknown> {
266→  if (kind === "project") {
267→    return {
268→      name: text,
269→      status: "active",
270→      ...(embedding ? { embedding } : {}),
271→      created_at: now,
272→      updated_at: now,
273→    };
274→  }
275→
276→  if (kind === "feature") {
277→    return {
278→      name: text,
279→      status: "active",
280→      ...(embedding ? { embedding } : {}),
281→      created_at: now,
282→      updated_at: now,
283→    };
284→  }
285→
286→  if (kind === "task") {
287→    return {
288→      title: text,
289→      status: "open",
290→      extraction_confidence: confidence,
291→      extracted_at: now,
292→      ...(sourceMessageRecord ? { source_message: sourceMessageRecord } : {}),
293→      ...(embedding ? { embedding } : {}),
294→      ...(category ? { category } : {}),
295→      ...(priority ? { priority } : {}),
296→      created_at: now,
297→      updated_at: now,
298→    };
299→  }
300→
301→  if (kind === "decision") {
302→    return {
303→      summary: text,
304→      status: "extracted",
305→      extraction_confidence: confidence,
306→      extracted_at: now,
307→      ...(sourceMessageRecord ? { source_message: sourceMessageRecord } : {}),
308→      ...(embedding ? { embedding } : {}),
309→      ...(category ? { category } : {}),
310→      ...(priority ? { priority } : {}),
311→      created_at: now,
312→      updated_at: now,
313→    };
314→  }
315→
316→  // question (fallthrough)
317→  return {
318→    text,
319→    status: "open",
320→    extraction_confidence: confidence,
321→    extracted_at: now,
322→    ...(sourceMessageRecord ? { source_message: sourceMessageRecord } : {}),
323→    ...(embedding ? { embedding } : {}),
324→    ...(category ? { category } : {}),
325→    ...(priority ? { priority } : {}),
326→    created_at: now,
327→    updated_at: now,
328→  };
329→}
330→
331→export async function loadWorkspaceKindCandidates(
332→  surreal: Surreal,
333→  workspaceRecord: RecordId<"workspace", string>,
334→  kind: ExtractableEntityKind,
335→): Promise<CandidateEntityRow[]> {
336→  if (kind === "project") {
337→    const [rows] = await surreal
338→      .query<[CandidateEntityRow[]]>(
339→        "SELECT id, name AS text, embedding FROM project WHERE id IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace);",
340→        { workspace: workspaceRecord },
341→      )
342→      .collect<[CandidateEntityRow[]]>();
343→    return rows;
344→  }
345→
346→  if (kind === "person") {
347→    const [rows] = await surreal
348→      .query<[CandidateEntityRow[]]>(
349→        "SELECT id, name AS text, embedding FROM person WHERE id IN (SELECT VALUE `in` FROM member_of WHERE out = $workspace);",
350→        { workspace: workspaceRecord },
351→      )
352→      .collect<[CandidateEntityRow[]]>();
353→    return rows;
354→  }
355→
356→  if (kind === "feature") {
357→    const [rows] = await surreal
358→      .query<[CandidateEntityRow[]]>(
359→        [
360→          "SELECT id, name AS text, embedding",
361→          "FROM feature",
362→          "WHERE id IN (",
363→          "  SELECT VALUE out",
364→          "  FROM has_feature",
365→          "  WHERE `in` IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace)",
366→          ");",
367→        ].join(" "),
368→        { workspace: workspaceRecord },
369→      )
370→      .collect<[CandidateEntityRow[]]>();
371→    return rows;
372→  }
373→
374→  if (kind === "task") {
375→    const [rows] = await surreal
376→      .query<[CandidateEntityRow[]]>(
377→        [
378→          "SELECT id, title AS text, embedding",
379→          "FROM task",
380→          "WHERE id IN (",
381→          "  SELECT VALUE `in`",
382→          "  FROM belongs_to",
383→          "  WHERE out IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace)",
384→          ")",
385→          "OR source_message IN (",
386→          "  SELECT VALUE id",
387→          "  FROM message",
388→          "  WHERE conversation IN (SELECT VALUE id FROM conversation WHERE workspace = $workspace)",
389→          ");",
390→        ].join(" "),
391→        { workspace: workspaceRecord },
392→      )
393→      .collect<[CandidateEntityRow[]]>();
394→    return uniqueCandidateRows(rows);
395→  }
396→
397→  if (kind === "decision") {
398→    const [rows] = await surreal
399→      .query<[CandidateEntityRow[]]>(
400→        [
401→          "SELECT id, summary AS text, embedding",
402→          "FROM decision",
403→          "WHERE id IN (",
404→          "  SELECT VALUE `in`",
405→          "  FROM belongs_to",
406→          "  WHERE out IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace)",
407→          ")",
408→          "OR source_message IN (",
409→          "  SELECT VALUE id",
410→          "  FROM message",
411→          "  WHERE conversation IN (SELECT VALUE id FROM conversation WHERE workspace = $workspace)",
412→          ");",
413→        ].join(" "),
414→        { workspace: workspaceRecord },
415→      )
416→      .collect<[CandidateEntityRow[]]>();
417→    return uniqueCandidateRows(rows);
418→  }
419→
420→  const [rows] = await surreal
421→    .query<[CandidateEntityRow[]]>(
422→      [
423→        "SELECT id, text AS text, embedding",
424→        "FROM question",
425→        "WHERE id IN (",
426→        "  SELECT VALUE `in`",
427→        "  FROM belongs_to",
428→        "  WHERE out IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace)",
429→        ")",
430→        "OR source_message IN (",
431→        "  SELECT VALUE id",
432→        "  FROM message",
