 11→import type { SourceRecord } from "../extraction/types";
 12→import type { CommitInput, ProcessCommitResult, ProcessWebhookInput, ProcessWebhookResult } from "./types";
 13→
 14→export async function processGitCommits(input: ProcessWebhookInput): Promise<ProcessWebhookResult> {
 15→  const startedAt = performance.now();
 16→  const workspaceId = input.workspaceRecord.id as string;
 17→
 18→  logInfo("webhook.commits.started", "Processing commits", {
 19→    workspaceId,
 20→    repository: input.event.repository.full_name,
 21→    commitCount: input.event.commits.length,
 22→  });
 23→
 24→  const projects = await loadWorkspaceProjects(input.surreal, input.workspaceRecord);
 25→  const projectNames = projects.map((p) => p.name);
 26→
 27→  const [workspaceRows] = await input.surreal
 28→    .query<[Array<{ name: string }>]>("SELECT name FROM $workspace LIMIT 1;", {
 29→      workspace: input.workspaceRecord,
 30→    })
 31→    .collect<[Array<{ name: string }>]>();
 32→  const workspaceName = workspaceRows[0]?.name;
 33→
 34→  const result: ProcessWebhookResult = {
 35→    commitsProcessed: 0,
 36→    commitsSkipped: 0,
 37→    totalEntities: 0,
 38→    totalRelationships: 0,
 39→    autoLinkedDecisions: [],
 40→    observationsCreated: [],
 41→  };
 42→
 43→  for (const rawCommit of input.event.commits) {
 44→    const commit: CommitInput = {
 45→      sha: rawCommit.id,
 46→      message: rawCommit.message,
 47→      authoredAt: rawCommit.timestamp,
 48→      authorName: rawCommit.author.name,
 49→      authorEmail: rawCommit.author.email,
 50→      authorUsername: rawCommit.author.username,
 51→      url: rawCommit.url,
 52→      repository: input.event.repository.full_name,
 53→    };
 54→
 55→    try {
 56→      const commitResult = await processCommit({
 57→        surreal: input.surreal,
 58→        extractionModel: input.extractionModel,
 59→        embeddingModel: input.embeddingModel,
 60→        embeddingDimension: input.embeddingDimension,
 61→        extractionStoreThreshold: input.extractionStoreThreshold,
 62→        extractionModelId: input.extractionModelId,
 63→        workspaceRecord: input.workspaceRecord,
 64→        commit,
 65→        workspaceName,
 66→        projectNames,
 67→        autoLinkThreshold: input.autoLinkThreshold,
 68→        now: new Date(),
 69→      });
 70→
 71→      result.commitsProcessed += 1;
 72→      result.totalEntities += commitResult.entities.length;
 73→      result.totalRelationships += commitResult.relationships.length;
 74→      result.autoLinkedDecisions.push(...commitResult.autoLinkedDecisions);
 75→      result.observationsCreated.push(...commitResult.observationsCreated);
 76→    } catch (error) {
 77→      logError("webhook.commit.failed", "Failed to process commit", error, {
 78→        workspaceId,
 79→        sha: commit.sha,
 80→      });
 81→      result.commitsSkipped += 1;
 82→    }
 83→  }
 84→
 85→  logInfo("webhook.commits.completed", "Finished processing commits", {
 86→    workspaceId,
 87→    ...result,
 88→    durationMs: elapsedMs(startedAt),
 89→  });
 90→
 91→  return result;
 92→}
